// ---------- UPTIME ----------
String getUptime() {

    unsigned long sec = millis() / 1000;

    int h = sec / 3600;
    int m = (sec % 3600) / 60;
    int s = sec % 60;

    char buf[12];
    sprintf(buf, "%02d:%02d:%02d", h, m, s);

    return String(buf);
}

// ---------- INIT ----------
void DashboardDisplay::begin() {

    Wire.begin(18,17);

    if(!display.begin(SSD1306_SWITCHCAPVCC, 0x3C)) {
        while(true);
    }

    display.clearDisplay();
    display.display();
}

// ---------- RENDER ----------
void DashboardDisplay::render() {

    display.clearDisplay();

    bool isSink = RoleController::getRole() == ROLE_SINK;
    String nodeID = NodeIdentity::getNodeID();

    // Background
    display.drawBitmap(0, 56, image_Background_bits, 128, 11, 1);
    display.drawBitmap(1, -4, image_Background_bits, 128, 11, 1);

    display.setTextColor(1);
    display.setTextWrap(false);
    display.setFont(&Org_01);

    // Title
    display.setCursor(18, 19);
    display.print("AAYA-MESH SYSTEM");

    // Mode
    display.setCursor(38, 32);
    display.print("MODE:");

    if(isSink)
        display.print("SINK");
    else
        display.print("COLLECTOR");

    // Overlay
    display.drawBitmap(0, 0, image_Layer_11_bits, 128, 60, 1);

    // NodeID
    display.setCursor(17, 56);
    display.print(nodeID);

    // Version
    display.setCursor(97, 56);
    display.print("V2.1.4");

    // Uptime
    display.setCursor(38, 43);
    display.print("UP-Time:");
    display.print(getUptime());

    // Face icon
    display.drawBitmap(4, 29, image_FaceNormal_bits, 29, 14, 1);

    display.display();
}